export enum Category {
  CAT_I = 'Category-I (Class I to V)',
  CAT_II = 'Category-II (Class VI to VIII)'
}

export interface SyllabusSection {
  id: string;
  title: string;
  marks: number;
  description: string;
  topics: string[];
}

export interface Question {
  id: string;
  subject: string;
  questionEn: string;
  questionOd: string;
  optionsEn: string[];
  optionsOd: string[];
  correctOptionIndex: number;
  explanationEn: string;
  explanationOd: string;
}

export interface FileData {
  data: string;
  mimeType: string;
  name: string;
}

export interface AppState {
  category: Category;
  selectedSectionId: string;
  questions: Question[];
  loading: boolean;
  error: string | null;
  language: 'en' | 'od';
  uploadedFile: FileData | null;
  studyMode: boolean; // If true, show answers immediately
}

import { GoogleGenAI, Type } from "@google/genai";
import { Question, FileData } from "../types";

export async function generatePracticeQuestions(
  subjectTitle: string,
  topics: string[],
  categoryName: string,
  fileData: FileData | null
): Promise<Question[]> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const textPart = {
    text: `
    Act as an expert examiner for the Odisha Junior Teacher (Schematic) exam. 
    Generate 5 high-quality Multiple Choice Questions (MCQs) for the subject "${subjectTitle}" under "${categoryName}".
    Topics to cover: ${topics.join(", ")}.

    ${fileData ? "CRITICAL: A reference document has been provided. Use the content of the PDF to generate relevant, specific, and accurate questions aligned with this source material." : ""}

    CRITICAL REQUIREMENTS:
    1. Each question MUST be bilingual: provide it in English and Odia.
    2. Follow the exam pattern: 4 options, only 1 correct answer.
    3. Include a detailed explanation for the correct answer in both English and Odia.
    4. The difficulty level should be appropriate for Primary/Upper Primary teachers as per the syllabus.
    5. For Odia translations, use clear, formal academic Odia suitable for teaching exams.
    6. Ensure the explanation is comprehensive and helps the student understand the core concept.
  `};

  const parts: any[] = [textPart];

  if (fileData) {
    parts.push({
      inlineData: {
        data: fileData.data,
        mimeType: fileData.mimeType,
      }
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              subject: { type: Type.STRING },
              questionEn: { type: Type.STRING },
              questionOd: { type: Type.STRING },
              optionsEn: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              },
              optionsOd: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              },
              correctOptionIndex: { type: Type.INTEGER },
              explanationEn: { type: Type.STRING },
              explanationOd: { type: Type.STRING }
            },
            required: [
              "id", "questionEn", "questionOd", "optionsEn", "optionsOd", 
              "correctOptionIndex", "explanationEn", "explanationOd"
            ]
          }
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const questions: Question[] = JSON.parse(text);
    return questions.map(q => ({ ...q, subject: subjectTitle }));
  } catch (error) {
    console.error("Error generating questions:", error);
    throw error;
  }
}

import React, { useState, useEffect } from 'react';
import { Question } from '../types';

interface QuestionCardProps {
  question: Question;
  lang: 'en' | 'od';
  index: number;
  autoShowSolution?: boolean;
}

export const QuestionCard: React.FC<QuestionCardProps> = ({ question, lang, index, autoShowSolution = false }) => {
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [showSolution, setShowSolution] = useState(autoShowSolution);

  useEffect(() => {
    if (autoShowSolution) {
      setShowSolution(true);
    }
  }, [autoShowSolution]);

  const isOdia = lang === 'od';
  const qText = isOdia ? question.questionOd : question.questionEn;
  const options = isOdia ? question.optionsOd : question.optionsEn;

  const correctOptionLabel = String.fromCharCode(65 + question.correctOptionIndex);
  const correctOptionEn = question.optionsEn[question.correctOptionIndex];
  const correctOptionOd = question.optionsOd[question.correctOptionIndex];

  const solutionVisible = showSolution || selectedOption !== null;

  return (
    <div className="question-card bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden mb-8 transition-all hover:shadow-md">
      {/* Question Header */}
      <div className="p-6">
        <div className="flex justify-between items-start mb-4">
          <span className="inline-block px-3 py-1 bg-indigo-50 text-indigo-700 text-xs font-bold rounded-full uppercase tracking-wider">
            {isOdia ? 'ପ୍ରଶ୍ନ' : 'Question'} {index + 1}
          </span>
          <span className="text-slate-400 text-xs italic no-print">
            JT Exam Standard
          </span>
        </div>

        <h3 className={`text-lg font-semibold mb-6 text-slate-800 leading-relaxed ${isOdia ? 'odia-font' : ''}`}>
          {qText}
        </h3>

        {/* Options List */}
        <div className="space-y-3">
          {options.map((option, idx) => {
            let variantClasses = "border-slate-200 hover:border-indigo-300 hover:bg-indigo-50";

            if (solutionVisible) {
              if (idx === question.correctOptionIndex) {
                variantClasses = "border-emerald-500 bg-emerald-50 text-emerald-800 ring-2 ring-emerald-200 ring-offset-1";
              } else if (idx === selectedOption) {
                variantClasses = "border-rose-500 bg-rose-50 text-rose-800";
              } else {
                variantClasses = "border-slate-200 opacity-50";
              }
            }

            return (
              <button
                key={idx}
                disabled={solutionVisible}
                onClick={() => setSelectedOption(idx)}
                className={`w-full text-left p-4 rounded-lg border-2 transition-all flex items-center group ${variantClasses} ${isOdia ? 'odia-font' : ''}`}
              >
                <span className={`w-8 h-8 flex items-center justify-center rounded-full border border-current mr-4 font-bold text-sm ${solutionVisible && idx === question.correctOptionIndex ? 'bg-emerald-500 text-white border-emerald-500' : ''}`}>
                  {String.fromCharCode(65 + idx)}
                </span>
                <span className="flex-1 font-medium">{option}</span>
              </button>
            );
          })}
        </div>

        {/* Reveal Toggle for Web */}
        {!autoShowSolution && (
          <div className="mt-6 flex justify-between items-center no-print">
            {!solutionVisible ? (
              <button 
                onClick={() => setShowSolution(true)}
                className="text-indigo-600 text-sm font-bold hover:text-indigo-800 flex items-center group"
              >
                <svg className="w-4 h-4 mr-1 transition-transform group-hover:scale-110" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path></svg>
                {isOdia ? 'ଉତ୍ତର ଦେଖନ୍ତୁ' : 'Show Solution'}
              </button>
            ) : (
              <div className="flex items-center text-slate-500 text-xs italic">
                <svg className="w-4 h-4 mr-1 text-emerald-500" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd"></path></svg>
                {isOdia ? 'ସମାଧାନ ତଳେ ଦିଆଯାଇଛି' : 'Solution displayed below'}
              </div>
            )}
          </div>
        )}
      </div>

      {/* Bilingual Solution Section */}
      <div className={`border-t-2 border-dashed border-indigo-100 bg-indigo-50/20 ${solutionVisible ? 'block' : 'hidden print:block'}`}>
        <div className="p-6 space-y-6">
          <div className="flex items-center space-x-2 text-indigo-900 font-extrabold text-sm uppercase tracking-tighter border-b border-indigo-200 pb-2">
            <svg className="w-5 h-5 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg>
            <span>Detailed Explanation / ବିସ୍ତୃତ ବ୍ୟାଖ୍ୟା</span>
          </div>

          {/* Correct Answer Row */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="bg-white p-4 rounded-xl border border-emerald-100 shadow-sm ring-1 ring-emerald-50">
              <p className="text-[10px] font-bold text-emerald-600 uppercase mb-1 flex items-center">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full mr-1.5"></span>
                Correct Answer (EN)
              </p>
              <p className="font-bold text-slate-800">Option {correctOptionLabel}: {correctOptionEn}</p>
            </div>
            <div className="bg-white p-4 rounded-xl border border-emerald-100 shadow-sm ring-1 ring-emerald-50 odia-font">
              <p className="text-[10px] font-bold text-emerald-600 uppercase mb-1 flex items-center">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full mr-1.5"></span>
                ସଠିକ୍ ଉତ୍ତର (ଓଡ଼ିଆ)
              </p>
              <p className="font-bold text-slate-800 text-lg">ବିକଳ୍ପ {correctOptionLabel}: {correctOptionOd}</p>
            </div>
          </div>

          {/* Detailed Explanation Row */}
          <div className="space-y-4">
            <div className="relative pl-6 py-2 border-l-4 border-indigo-400 bg-white/50 rounded-r-lg">
              <p className="text-[10px] font-bold text-indigo-600 uppercase mb-2 tracking-widest">Logic & Concept (English)</p>
              <p className="text-sm text-slate-700 leading-relaxed font-medium">{question.explanationEn}</p>
            </div>
            <div className="relative pl-6 py-2 border-l-4 border-indigo-400 bg-white/50 rounded-r-lg odia-font">
              <p className="text-[10px] font-bold text-indigo-600 uppercase mb-2 tracking-widest">ଯୁକ୍ତି ଏବଂ ଧାରଣା (ଓଡ଼ିଆ)</p>
              <p className="text-sm text-slate-700 leading-relaxed font-medium text-lg">{question.explanationOd}</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Category, AppState, Question, FileData } from './types';
import { SYLLABUS_DATA } from './constants';
import { generatePracticeQuestions } from './services/geminiService';
import { QuestionCard } from './components/QuestionCard';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    category: Category.CAT_I,
    selectedSectionId: SYLLABUS_DATA[Category.CAT_I][0].id,
    questions: [],
    loading: false,
    error: null,
    language: 'en',
    uploadedFile: null,
    studyMode: true // Default to true as per user request to see answers/explanations
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const fetchQuestions = useCallback(async (sectionId: string, category: Category, fileToUse?: FileData | null) => {
    const section = SYLLABUS_DATA[category].find(s => s.id === sectionId);
    if (!section) return;

    setState(prev => ({ ...prev, loading: true, error: null, questions: [] }));

    try {
      const qs = await generatePracticeQuestions(
        section.title, 
        section.topics, 
        category, 
        fileToUse !== undefined ? fileToUse : state.uploadedFile
      );
      setState(prev => ({ ...prev, questions: qs, loading: false }));
    } catch (err) {
      setState(prev => ({ ...prev, error: "Failed to generate questions. Please try again.", loading: false }));
    }
  }, [state.uploadedFile, state.category]);

  useEffect(() => {
    fetchQuestions(state.selectedSectionId, state.category);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleCategoryChange = (cat: Category) => {
    const firstSectionId = SYLLABUS_DATA[cat][0].id;
    setState(prev => ({ ...prev, category: cat, selectedSectionId: firstSectionId }));
    fetchQuestions(firstSectionId, cat);
  };

  const handleSectionChange = (id: string) => {
    setState(prev => ({ ...prev, selectedSectionId: id }));
    fetchQuestions(id, state.category);
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (file.type !== 'application/pdf') {
      alert('Please upload a PDF file.');
      return;
    }

    const reader = new FileReader();
    reader.onload = () => {
      const base64 = (reader.result as string).split(',')[1];
      const newFileData = {
        data: base64,
        mimeType: file.type,
        name: file.name
      };
      setState(prev => ({ ...prev, uploadedFile: newFileData }));
      // Immediately regenerate questions with the new file context
      fetchQuestions(state.selectedSectionId, state.category, newFileData);
    };
    reader.readAsDataURL(file);
  };

  const clearFile = () => {
    setState(prev => ({ ...prev, uploadedFile: null }));
    if (fileInputRef.current) fileInputRef.current.value = '';
    fetchQuestions(state.selectedSectionId, state.category, null);
  };

  const handleExportPDF = () => {
    window.print();
  };

  const currentSection = SYLLABUS_DATA[state.category].find(s => s.id === state.selectedSectionId);

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar */}
      <aside className="w-full md:w-80 bg-slate-900 text-slate-100 flex-shrink-0 flex flex-col h-auto md:h-screen md:sticky md:top-0 border-r border-slate-800">
        <div className="p-6 border-b border-slate-800">
          <h1 className="text-xl font-bold flex items-center">
            <span className="bg-indigo-600 p-2 rounded-lg mr-3 shadow-lg shadow-indigo-500/20">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253"></path>
              </svg>
            </span>
            Junior Teacher Prep
          </h1>
          <p className="text-slate-400 text-[10px] mt-2 uppercase tracking-[0.2em] font-black">Bilingual Mastery Hub</p>
        </div>

        <div className="p-4 space-y-6 flex-1 overflow-y-auto custom-scrollbar">
          {/* PDF Analysis Tool */}
          <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700">
            <label className="block text-[10px] font-bold text-indigo-400 uppercase mb-3 flex items-center">
              <svg className="w-3 h-3 mr-1" fill="currentColor" viewBox="0 0 20 20"><path d="M9 2a2 2 0 00-2 2v8a2 2 0 002 2h6a2 2 0 002-2V6.414A2 2 0 0016.414 5L14 2.586A2 2 0 0012.586 2H9z"></path><path d="M3 8a2 2 0 012-2v10h8a2 2 0 01-2 2H5a2 2 0 01-2-2V8z"></path></svg>
              Smart PDF Analysis
            </label>
            {!state.uploadedFile ? (
              <div 
                onClick={() => fileInputRef.current?.click()}
                className="cursor-pointer border-2 border-dashed border-slate-600 rounded-lg p-4 text-center hover:border-indigo-500 hover:bg-slate-800 transition-all group"
              >
                <div className="text-slate-400 group-hover:text-indigo-400 mb-2 flex justify-center">
                  <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
                </div>
                <p className="text-xs text-slate-300 font-medium">Upload PDF Study Material</p>
                <p className="text-[10px] text-slate-500 mt-1">AI will generate questions based on it</p>
              </div>
            ) : (
              <div className="bg-slate-900 p-3 rounded-lg border border-indigo-500/30 flex items-center justify-between">
                <div className="flex items-center space-x-2 truncate">
                  <div className="bg-indigo-600/20 p-2 rounded text-indigo-400">
                    <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4 4a2 2 0 012-2h4.586A2 2 0 0112 2.586L15.414 6A2 2 0 0116 7.414V16a2 2 0 01-2 2H6a2 2 0 01-2-2V4z" clipRule="evenodd"></path></svg>
                  </div>
                  <span className="text-xs font-medium text-slate-200 truncate">{state.uploadedFile.name}</span>
                </div>
                <button onClick={clearFile} className="text-slate-500 hover:text-rose-400 p-1">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
                </button>
              </div>
            )}
            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleFileUpload} 
              accept="application/pdf" 
              className="hidden" 
            />
          </div>

          {/* Category Toggle */}
          <div>
            <label className="block text-[10px] font-bold text-slate-500 uppercase mb-2">Syllabus Category</label>
            <div className="grid grid-cols-1 gap-2">
              {Object.values(Category).map(cat => (
                <button
                  key={cat}
                  onClick={() => handleCategoryChange(cat)}
                  className={`px-4 py-2.5 text-sm rounded-lg text-left transition-all font-semibold ${state.category === cat ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/40' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}
                >
                  {cat}
                </button>
              ))}
            </div>
          </div>

          {/* Subject Navigation */}
          <div>
            <label className="block text-[10px] font-bold text-slate-500 uppercase mb-2">Subject Areas</label>
            <nav className="space-y-1">
              {SYLLABUS_DATA[state.category].map(section => (
                <button
                  key={section.id}
                  onClick={() => handleSectionChange(section.id)}
                  className={`w-full text-left px-4 py-3 rounded-lg text-sm transition-all flex items-center group ${state.selectedSectionId === section.id ? 'bg-indigo-950/30 text-white border-l-4 border-indigo-500 shadow-inner' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
                >
                  <span className={`w-2 h-2 rounded-full mr-3 ${state.selectedSectionId === section.id ? 'bg-indigo-400 shadow-[0_0_8px_rgba(129,140,248,0.8)]' : 'bg-slate-700'}`}></span>
                  <span className="truncate">{section.title}</span>
                  <span className="ml-auto text-[10px] bg-slate-800 px-1.5 py-0.5 rounded opacity-60">{section.marks}M</span>
                </button>
              ))}
            </nav>
          </div>

          {/* Settings / Mode Toggle */}
          <div className="pt-4 border-t border-slate-800">
            <button 
              onClick={() => setState(prev => ({ ...prev, studyMode: !prev.studyMode }))}
              className={`w-full flex items-center justify-between p-3 rounded-lg border transition-all ${state.studyMode ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400' : 'bg-slate-800 border-slate-700 text-slate-400'}`}
            >
              <div className="flex items-center text-xs font-bold uppercase tracking-wider">
                <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253"></path></svg>
                Study Mode
              </div>
              <div className={`w-8 h-4 rounded-full relative transition-colors ${state.studyMode ? 'bg-emerald-500' : 'bg-slate-600'}`}>
                <div className={`absolute top-0.5 w-3 h-3 rounded-full bg-white transition-transform ${state.studyMode ? 'left-4.5' : 'left-0.5'}`}></div>
              </div>
            </button>
            <p className="text-[10px] text-slate-500 mt-2 italic px-1">Always show answers & explanations for rapid learning.</p>
          </div>
        </div>

        <div className="p-6 bg-slate-950 border-t border-slate-800">
           <div className="flex items-center space-x-3 text-slate-400 text-[10px]">
              <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center text-white shadow-lg shadow-indigo-500/20">
                <span className="font-black">JT</span>
              </div>
              <div>
                <p className="font-bold text-slate-200">Exam Mode: Computer Based</p>
                <p className="font-medium">+2 Correct / -0.5 Wrong</p>
              </div>
           </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 bg-slate-50 min-h-screen">
        {/* Print Only Header */}
        <div className="print-header px-6 py-4">
          <h1 className="text-2xl font-bold">Odisha Junior Teacher (Schematic) - Practice Questions</h1>
          <p className="text-slate-600 mt-2">{state.category} | {currentSection?.title}</p>
          <p className="text-sm text-slate-500 mt-1">Generated by Odisha Junior Teacher Prep Hub</p>
        </div>

        {/* Desktop Header */}
        <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 sticky top-0 z-10 px-6 py-4 flex flex-col lg:flex-row justify-between items-center gap-4">
          <div className="flex flex-col flex-1">
            <h2 className="text-xl font-extrabold text-slate-800 flex items-center">
              {currentSection?.title}
              {state.uploadedFile && (
                <span className="ml-3 px-2 py-0.5 bg-indigo-100 text-indigo-700 text-[10px] rounded border border-indigo-200 uppercase font-black">
                  Analyzed from PDF
                </span>
              )}
            </h2>
            <p className="text-slate-500 text-sm hidden sm:block font-medium">{currentSection?.description}</p>
          </div>

          <div className="flex flex-wrap items-center gap-3">
            <button
              onClick={handleExportPDF}
              className="flex items-center space-x-2 px-4 py-2 border border-slate-200 rounded-lg text-slate-600 text-sm font-bold hover:bg-slate-50 hover:text-indigo-600 hover:border-indigo-100 transition-all no-print shadow-sm"
