          <span className="inline-block px-3 py-1 bg-indigo-50 text-indigo-700 text-xs font-bold rounded-full uppercase tracking-wider">
            {lang === 'od' ? 'ପ୍ରଶ୍ନ' : 'Question'} {index + 1}
