import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Category, AppState, Question, FileData } from './types';
import { SYLLABUS_DATA } from './constants';
import { generatePracticeQuestions } from './services/geminiService';
import { QuestionCard } from './components/QuestionCard';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    category: Category.CAT_I,
    selectedSectionId: SYLLABUS_DATA[Category.CAT_I][0].id,
    questions: [],
    loading: false,
    error: null,
    language: 'en',
    uploadedFile: null,
    studyMode: true // Default to true as per user request to see answers/explanations
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const fetchQuestions = useCallback(async (sectionId: string, category: Category, fileToUse?: FileData | null) => {
    const section = SYLLABUS_DATA[category].find(s => s.id === sectionId);
    if (!section) return;

    setState(prev => ({ ...prev, loading: true, error: null, questions: [] }));

    try {
      const qs = await generatePracticeQuestions(
        section.title, 
        section.topics, 
        category, 
        fileToUse !== undefined ? fileToUse : state.uploadedFile
      );
      setState(prev => ({ ...prev, questions: qs, loading: false }));
    } catch (err) {
      setState(prev => ({ ...prev, error: "Failed to generate questions. Please try again.", loading: false }));
    }
  }, [state.uploadedFile, state.category]);

  useEffect(() => {
    fetchQuestions(state.selectedSectionId, state.category);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleCategoryChange = (cat: Category) => {
    const firstSectionId = SYLLABUS_DATA[cat][0].id;
    setState(prev => ({ ...prev, category: cat, selectedSectionId: firstSectionId }));
    fetchQuestions(firstSectionId, cat);
  };

  const handleSectionChange = (id: string) => {
    setState(prev => ({ ...prev, selectedSectionId: id }));
    fetchQuestions(id, state.category);
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (file.type !== 'application/pdf') {
      alert('Please upload a PDF file.');
      return;
    }

    const reader = new FileReader();
    reader.onload = () => {
      const base64 = (reader.result as string).split(',')[1];
      const newFileData = {
        data: base64,
        mimeType: file.type,
        name: file.name
      };
      setState(prev => ({ ...prev, uploadedFile: newFileData }));
      // Immediately regenerate questions with the new file context
      fetchQuestions(state.selectedSectionId, state.category, newFileData);
    };
    reader.readAsDataURL(file);
  };

  const clearFile = () => {
    setState(prev => ({ ...prev, uploadedFile: null }));
    if (fileInputRef.current) fileInputRef.current.value = '';
    fetchQuestions(state.selectedSectionId, state.category, null);
  };

  const handleDownloadPDF = () => {
    // Setting document title helps the printed PDF file name in most browsers
    const originalTitle = document.title;
    const sectionName = SYLLABUS_DATA[state.category].find(s => s.id === state.selectedSectionId)?.title || "PracticeSet";
    document.title = `JT_Exam_Prep_${sectionName}_Bilingual`;
    window.print();
    document.title = originalTitle;
  };

  const currentSection = SYLLABUS_DATA[state.category].find(s => s.id === state.selectedSectionId);

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar */}
      <aside className="w-full md:w-80 bg-slate-900 text-slate-100 flex-shrink-0 flex flex-col h-auto md:h-screen md:sticky md:top-0 border-r border-slate-800">
        <div className="p-6 border-b border-slate-800">
          <h1 className="text-xl font-bold flex items-center">
            <span className="bg-indigo-600 p-2 rounded-lg mr-3 shadow-lg shadow-indigo-500/20">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253"></path>
              </svg>
            </span>
            Junior Teacher Prep
          </h1>
          <p className="text-slate-400 text-[10px] mt-2 uppercase tracking-[0.2em] font-black">Bilingual Mastery Hub</p>
        </div>

        <div className="p-4 space-y-6 flex-1 overflow-y-auto custom-scrollbar">
          {/* PDF Analysis Tool */}
          <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700">
            <label className="block text-[10px] font-bold text-indigo-400 uppercase mb-3 flex items-center">
              <svg className="w-3 h-3 mr-1" fill="currentColor" viewBox="0 0 20 20"><path d="M9 2a2 2 0 00-2 2v8a2 2 0 002 2h6a2 2 0 002-2V6.414A2 2 0 0016.414 5L14 2.586A2 2 0 0012.586 2H9z"></path><path d="M3 8a2 2 0 012-2v10h8a2 2 0 01-2 2H5a2 2 0 01-2-2V8z"></path></svg>
              Smart PDF Analysis
            </label>
            {!state.uploadedFile ? (
              <div 
                onClick={() => fileInputRef.current?.click()}
                className="cursor-pointer border-2 border-dashed border-slate-600 rounded-lg p-4 text-center hover:border-indigo-500 hover:bg-slate-800 transition-all group"
              >
                <div className="text-slate-400 group-hover:text-indigo-400 mb-2 flex justify-center">
                  <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
                </div>
                <p className="text-xs text-slate-300 font-medium">Upload PDF Study Material</p>
                <p className="text-[10px] text-slate-500 mt-1">AI will generate questions based on it</p>
              </div>
            ) : (
              <div className="bg-slate-900 p-3 rounded-lg border border-indigo-500/30 flex items-center justify-between">
