          <div className="flex flex-wrap items-center gap-3 no-print">
            <div className="flex items-center bg-slate-100 rounded-full p-1 border border-slate-200 shadow-inner">
              <button
                onClick={() => setState(prev => ({ ...prev, language: 'en' }))}
