              <button
                onClick={() => setState(prev => ({ ...prev, language: 'od' }))}
                className={`px-6 py-1.5 rounded-full text-sm font-black transition-all odia-font ${state.language === 'od' ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500 hover:text-slate-800'}`}
              >
                ଓଡ଼ିଆ
              </button>
            </div>
          </div>
        </header>

        <div className="max-w-4xl mx-auto p-6 md:p-10">
          {state.loading ? (
            <div className="flex flex-col items-center justify-center py-24 space-y-6">
              <div className="w-20 h-20 border-4 border-slate-200 border-t-indigo-600 rounded-full animate-spin"></div>
              <p className="text-slate-800 font-black text-xl">Curating expert {state.viewMode.toLowerCase()}...</p>
            </div>
          ) : state.error ? (
            <div className="bg-rose-50 border-2 border-rose-100 rounded-2xl p-10 text-center">
              <p className="text-rose-900 font-extrabold text-xl mb-3">{state.error}</p>
              <button 
                onClick={() => fetchData(state.selectedSectionId, state.category, state.viewMode)}
