                <span className={`flex-shrink-0 w-8 h-8 flex items-center justify-center rounded-full border border-current mr-4 font-bold text-sm ${solutionVisible && idx === question.correctOptionIndex ? 'bg-emerald-500 text-white border-emerald-500' : 'bg-white'}`}>
                  {String.fromCharCode(65 + idx)}
