                <div className="flex-1 space-y-1">
                  <p className="font-semibold text-slate-700">{optionEn}</p>
                  <p className="font-medium text-indigo-800/80 odia-font text-lg leading-tight">{optionOd}</p>
                </div>
              </motion.button>
            );
          })}
