                <span>Detailed Explanation / ବିସ୍ତୃତ ବ୍ୟାଖ୍ୟା</span>
              </div>

              {/* Correct Answer Row */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="bg-white p-4 rounded-xl border border-emerald-100 shadow-sm ring-1 ring-emerald-50">
