                  <p className="font-bold text-slate-800">Option {correctOptionLabel}: {question.optionsEn[question.correctOptionIndex]}</p>
                </div>
                <div className="bg-white p-4 rounded-xl border border-emerald-100 shadow-sm ring-1 ring-emerald-50 odia-font">
