                    </div>
                    <div className="flex items-start">
                      <span className="text-indigo-400 mr-2 font-black">3.</span>
                      <span>Ensure <b>"Background Graphics"</b> is checked in options.</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Sidebar */}
      <aside className="w-full md:w-80 bg-slate-900 text-slate-100 flex-shrink-0 flex flex-col h-auto md:h-screen md:sticky md:top-0 border-r border-slate-800 z-20">
