          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 bg-slate-50 min-h-screen">
        {/* PRINT ONLY HEADER */}
        <div className="print-header px-10 pt-10 pb-6">
          <div className="border-4 border-slate-900 p-10 rounded-xl">
             <h1 className="text-3xl font-black uppercase text-slate-900 tracking-tighter mb-4 text-center">Odisha Junior Teacher (Schematic) Recruitment</h1>
             <p className="text-xl font-bold text-slate-700 mb-8 text-center bg-slate-100 py-3 rounded-lg">Official Mastery Series: {currentSection?.title} (Bilingual)</p>
             <div className="grid grid-cols-3 gap-8 text-xs font-black text-slate-600 uppercase tracking-widest">
