                  <span className="text-[10px] text-slate-400 mb-1">Exam Level</span>
                  <span>{state.category}</span>
                </div>
                <div className="flex flex-col text-center">
                  <span className="text-[10px] text-slate-400 mb-1">Total Questions</span>
                  <span>{state.questions.length} Items</span>
                </div>
                <div className="flex flex-col text-right">
                  <span className="text-[10px] text-slate-400 mb-1">Time Allowed</span>
                  <span>{Math.round(state.questions.length * 1.5)} Minutes</span>
                </div>
             </div>
          </div>
          <div className="mt-8 text-center text-[10px] text-slate-400 font-bold uppercase tracking-[0.3em]">
            Practice Set generated for offline study and mock exam purposes
