                {lang === 'od' ? 'ଉତ୍ତର ଦେଖନ୍ତୁ' : 'Show Solution'}
              </motion.button>
            ) : (
              <div className="flex items-center text-slate-500 text-xs italic">
                <svg className="w-4 h-4 mr-1 text-emerald-500" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd"></path></svg>
                {lang === 'od' ? 'ସମାଧାନ ତଳେ ଦିଆଯାଇଛି' : 'Solution displayed below'}
              </div>
            )}
          </div>
        )}
      </div>

      {/* Solution Section */}
      <AnimatePresence>
        {solutionVisible && (
          <motion.div 
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: "auto", opacity: 1 }}
            className={`border-t-2 border-dashed border-indigo-100 bg-indigo-50/20 overflow-hidden print:block`}
          >
            <div className="p-6 space-y-6">
              <div className="flex items-center space-x-2 text-indigo-900 font-extrabold text-sm uppercase tracking-tighter border-b border-indigo-200 pb-2">
                <svg className="w-5 h-5 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg>
                <span>{showEn && showOd ? 'Detailed Explanation / ବିସ୍ତୃତ ବ୍ୟାଖ୍ୟା' : showEn ? 'Detailed Explanation' : 'ବିସ୍ତୃତ ବ୍ୟାଖ୍ୟା'}</span>
              </div>

              {/* Correct Answer Row */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {showEn && (
                  <div className="bg-white p-4 rounded-xl border border-emerald-100 shadow-sm ring-1 ring-emerald-50">
                    <p className="text-[10px] font-bold text-emerald-600 uppercase mb-1 flex items-center">
                      <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full mr-1.5"></span>
                      Correct Answer (EN)
                    </p>
                    <p className="font-bold text-slate-800">Option {correctOptionLabel}: {question.optionsEn[question.correctOptionIndex]}</p>
                  </div>
                )}
                {showOd && (
                  <div className="bg-white p-4 rounded-xl border border-emerald-100 shadow-sm ring-1 ring-emerald-50 odia-font">
                    <p className="text-[10px] font-bold text-emerald-600 uppercase mb-1 flex items-center">
                      <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full mr-1.5"></span>
                      ସଠିକ୍ ଉତ୍ତର (ଓଡ଼ିଆ)
                    </p>
                    <p className="font-bold text-slate-800 text-lg">ବିକଳ୍ପ {correctOptionLabel}: {question.optionsOd[question.correctOptionIndex]}</p>
                  </div>
                )}
              </div>

              {/* Detailed Explanation Row */}
              <div className="space-y-4">
                {showEn && (
                  <div className="relative pl-6 py-2 border-l-4 border-indigo-400 bg-white/50 rounded-r-lg">
                    <p className="text-[10px] font-bold text-indigo-600 uppercase mb-2 tracking-widest">Logic & Concept (English)</p>
                    <p className="text-sm text-slate-700 leading-relaxed font-medium">{question.explanationEn}</p>
                  </div>
                )}
                {showOd && (
                  <div className="relative pl-6 py-2 border-l-4 border-indigo-400 bg-white/50 rounded-r-lg odia-font">
                    <p className="text-[10px] font-bold text-indigo-600 uppercase mb-2 tracking-widest">ଯୁକ୍ତି ଏବଂ ଧାରଣା (ଓଡ଼ିଆ)</p>
                    <p className="text-sm text-slate-700 leading-relaxed font-medium text-lg">{question.explanationOd}</p>
                  </div>
                )}
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Category, AppState, Question, Flashcard, FileData, ViewMode, PdfLanguage } from './types';
import { SYLLABUS_DATA } from './constants';
import { generatePracticeQuestions, generateFlashcards } from './services/geminiService';
import { QuestionCard } from './components/QuestionCard';
import { FlashcardSet } from './components/FlashcardSet';

const PDF_STEPS = [
  "Formatting bilingual question layout...",
  "Optimizing Noto Sans Odia rendering...",
  "Injecting official exam headers...",
  "Finalizing high-resolution worksheet...",
  "Opening System Print Engine..."
];

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    category: Category.CAT_I,
    selectedSectionId: SYLLABUS_DATA[Category.CAT_I][0].id,
    questions: [],
    flashcards: [],
    viewMode: ViewMode.QUIZ,
    loading: false,
    error: null,
    language: 'en',
    uploadedFile: null,
    studyMode: true,
    pdfConfig: {
      language: 'both',
      startRange: 1,
      endRange: 20
    }
  });

  const [pdfPrepStep, setPdfPrepStep] = useState<number>(-1);
  const [showPdfSettings, setShowPdfSettings] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const fetchData = useCallback(async (sectionId: string, category: Category, mode: ViewMode, fileToUse?: FileData | null) => {
    const section = SYLLABUS_DATA[category].find(s => s.id === sectionId);
    if (!section) return;

    setState(prev => ({ ...prev, loading: true, error: null }));

    try {
      const activeFile = fileToUse !== undefined ? fileToUse : state.uploadedFile;

      if (mode === ViewMode.QUIZ) {
        const qs = await generatePracticeQuestions(section.title, section.topics, category, activeFile);
        setState(prev => ({ 
          ...prev, 
          questions: qs, 
          loading: false,
          pdfConfig: { ...prev.pdfConfig, endRange: qs.length }
        }));
      } else {
        const cards = await generateFlashcards(section.title, section.topics, category, activeFile);
        setState(prev => ({ ...prev, flashcards: cards, loading: false }));
      }
    } catch (err) {
      setState(prev => ({ ...prev, error: "Failed to load content. Please try again.", loading: false }));
    }
  }, [state.uploadedFile]);

  useEffect(() => {
    fetchData(state.selectedSectionId, state.category, state.viewMode);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleCategoryChange = (cat: Category) => {
    const firstSectionId = SYLLABUS_DATA[cat][0].id;
    setState(prev => ({ ...prev, category: cat, selectedSectionId: firstSectionId }));
    fetchData(firstSectionId, cat, state.viewMode);
  };

  const handleSectionChange = (id: string) => {
    setState(prev => ({ ...prev, selectedSectionId: id }));
    fetchData(id, state.category, state.viewMode);
  };

  const toggleViewMode = (mode: ViewMode) => {
    if (mode === state.viewMode) return;
    setState(prev => ({ ...prev, viewMode: mode }));

    if ((mode === ViewMode.QUIZ && state.questions.length === 0) || 
        (mode === ViewMode.FLASHCARDS && state.flashcards.length === 0)) {
      fetchData(state.selectedSectionId, state.category, mode);
    }
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (file.type !== 'application/pdf') {
      alert('Please upload a PDF file.');
      return;
    }

    const reader = new FileReader();
    reader.onload = () => {
      const base64 = (reader.result as string).split(',')[1];
      const newFileData = {
        data: base64,
        mimeType: file.type,
        name: file.name
      };
      setState(prev => ({ ...prev, uploadedFile: newFileData, questions: [], flashcards: [] }));
      fetchData(state.selectedSectionId, state.category, state.viewMode, newFileData);
    };
    reader.readAsDataURL(file);
  };

  const clearFile = () => {
    setState(prev => ({ ...prev, uploadedFile: null, questions: [], flashcards: [] }));
    if (fileInputRef.current) fileInputRef.current.value = '';
    fetchData(state.selectedSectionId, state.category, state.viewMode, null);
  };

  const startPDFProcess = async () => {
    if (state.questions.length === 0 && state.viewMode === ViewMode.QUIZ) {
      alert("Please wait for questions to load before downloading.");
      return;
    }

    setShowPdfSettings(false);

    // Run through steps
    for (let i = 0; i < PDF_STEPS.length; i++) {
      setPdfPrepStep(i);
      await new Promise(r => setTimeout(r, 600));
    }

    // Trigger Print
    const sectionName = SYLLABUS_DATA[state.category].find(s => s.id === state.selectedSectionId)?.title || "Worksheet";
    const originalTitle = document.title;
    document.title = `JT_EXAM_PREP_${sectionName.replace(/\s+/g, '_')}_BILINGUAL`;

    window.print();

    document.title = originalTitle;
    setPdfPrepStep(-1);
  };

  const currentSection = SYLLABUS_DATA[state.category].find(s => s.id === state.selectedSectionId);

  const filteredQuestions = state.questions.slice(state.pdfConfig.startRange - 1, state.pdfConfig.endRange);

  return (
    <div className="min-h-screen flex flex-col md:flex-row overflow-x-hidden">
      {/* PDF PREPARATION OVERLAY */}
      <AnimatePresence>
        {pdfPrepStep >= 0 && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-[100] glass-prep flex items-center justify-center p-6 text-white"
          >
            <div className="max-w-md w-full bg-slate-800 rounded-3xl p-8 border border-slate-700 shadow-2xl relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-1 bg-slate-700">
                <motion.div 
                  initial={{ width: "0%" }}
                  animate={{ width: `${((pdfPrepStep + 1) / PDF_STEPS.length) * 100}%` }}
                  className="h-full bg-indigo-500 shadow-[0_0_15px_rgba(99,102,241,0.5)]"
                />
              </div>

              <div className="flex flex-col items-center">
                <div className="w-16 h-16 mb-6 bg-indigo-500/10 rounded-2xl flex items-center justify-center">
                  <motion.svg 
                    animate={{ rotate: 360 }}
                    transition={{ duration: 2, repeat: Infinity, ease: "linear" }}
                    className="w-10 h-10 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"
                  >
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path>
                  </motion.svg>
                </div>

                <h2 className="text-xl font-black mb-1">Generating PDF Bank</h2>
                <p className="text-slate-400 text-sm mb-8">Odisha Junior Teacher (Schematic) - Customized</p>

                <div className="w-full space-y-3 mb-10">
                  {PDF_STEPS.map((step, idx) => (
                    <motion.div 
                      key={idx}
                      initial={{ opacity: 0.3 }}
                      animate={{ 
                        opacity: idx === pdfPrepStep ? 1 : idx < pdfPrepStep ? 0.6 : 0.2,
                        x: idx === pdfPrepStep ? 5 : 0
                      }}
                      className="flex items-center space-x-3 text-xs font-bold"
                    >
                      <div className={`w-5 h-5 rounded-full flex items-center justify-center flex-shrink-0 transition-colors ${idx < pdfPrepStep ? 'bg-emerald-500' : idx === pdfPrepStep ? 'bg-indigo-500 animate-pulse' : 'bg-slate-700'}`}>
                        {idx < pdfPrepStep ? (
                          <svg className="w-3 h-3 text-white" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd"></path></svg>
                        ) : <span className="text-[8px]">{idx + 1}</span>}
                      </div>
                      <span className={idx === pdfPrepStep ? 'text-white' : 'text-slate-500'}>{step}</span>
                    </motion.div>
                  ))}
                </div>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* PDF SETTINGS MODAL */}
      <AnimatePresence>
        {showPdfSettings && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-[90] bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-6 no-print"
          >
            <motion.div 
              initial={{ scale: 0.9, y: 20 }}
              animate={{ scale: 1, y: 0 }}
              className="bg-white rounded-3xl p-8 max-w-lg w-full shadow-2xl border border-slate-200"
            >
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight">Customize PDF Export</h3>
                <button onClick={() => setShowPdfSettings(false)} className="text-slate-400 hover:text-rose-500 p-2">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
                </button>
              </div>

              <div className="space-y-6">
                {/* Language Filter */}
                <div>
                  <label className="block text-[10px] font-bold text-slate-500 uppercase mb-3">Language Inclusion</label>
                  <div className="grid grid-cols-3 gap-2">
                    {(['both', 'en', 'od'] as PdfLanguage[]).map(l => (
                      <button
                        key={l}
                        onClick={() => setState(p => ({ ...p, pdfConfig: { ...p.pdfConfig, language: l }}))}
                        className={`py-2 px-3 text-xs font-bold rounded-xl border-2 transition-all ${state.pdfConfig.language === l ? 'bg-indigo-600 border-indigo-600 text-white' : 'border-slate-100 text-slate-500 hover:border-indigo-100'}`}
                      >
                        {l === 'both' ? 'Bilingual' : l === 'en' ? 'English Only' : 'Odia Only'}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Range Selection */}
                <div>
                  <label className="block text-[10px] font-bold text-slate-500 uppercase mb-3">Question Range (Total: {state.questions.length})</label>
                  <div className="flex items-center space-x-4">
                    <div className="flex-1">
                      <p className="text-[10px] text-slate-400 mb-1 font-bold">FROM</p>
                      <input 
                        type="number" 
                        min="1" 
                        max={state.questions.length}
                        value={state.pdfConfig.startRange}
                        onChange={(e) => setState(p => ({ ...p, pdfConfig: { ...p.pdfConfig, startRange: Math.max(1, parseInt(e.target.value) || 1)}}))}
                        className="w-full bg-slate-50 border-2 border-slate-100 rounded-xl px-4 py-3 text-sm font-bold focus:border-indigo-500 outline-none"
                      />
                    </div>
                    <div className="flex-1">
                      <p className="text-[10px] text-slate-400 mb-1 font-bold">TO</p>
                      <input 
                        type="number" 
                        min={state.pdfConfig.startRange} 
                        max={state.questions.length}
                        value={state.pdfConfig.endRange}
                        onChange={(e) => setState(p => ({ ...p, pdfConfig: { ...p.pdfConfig, endRange: Math.min(state.questions.length, parseInt(e.target.value) || state.questions.length)}}))}
                        className="w-full bg-slate-50 border-2 border-slate-100 rounded-xl px-4 py-3 text-sm font-bold focus:border-indigo-500 outline-none"
                      />
                    </div>
                  </div>
                </div>

                <motion.button
                  whileHover={{ scale: 1.02 }}
                  whileTap={{ scale: 0.98 }}
                  onClick={startPDFProcess}
                  className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black text-sm shadow-xl shadow-slate-900/20"
                >
                  START EXPORT
                </motion.button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Sidebar */}
      <aside className="w-full md:w-80 bg-slate-900 text-slate-100 flex-shrink-0 flex flex-col h-auto md:h-screen md:sticky md:top-0 border-r border-slate-800 z-20">
        <div className="p-6 border-b border-slate-800">
          <motion.h1 
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            className="text-xl font-bold flex items-center"
          >
            <span className="bg-indigo-600 p-2 rounded-lg mr-3 shadow-lg shadow-indigo-500/20">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253"></path>
              </svg>
            </span>
            Junior Teacher Prep
          </motion.h1>
          <p className="text-slate-400 text-[10px] mt-2 uppercase tracking-[0.2em] font-black">Bilingual Mastery Hub</p>
        </div>

        <div className="p-4 space-y-6 flex-1 overflow-y-auto custom-scrollbar">
          {/* Main Download Action */}
          <motion.button
             whileHover={{ scale: 1.02 }}
             whileTap={{ scale: 0.95 }}
             onClick={() => setShowPdfSettings(true)}
             className="w-full bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl py-4 flex flex-col items-center justify-center font-black shadow-xl shadow-indigo-900/30 transition-all no-print mb-4"
          >
             <div className="flex items-center space-x-2 text-sm mb-0.5">
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
               <span>DOWNLOAD WORKSHEET</span>
             </div>
             <span className="text-[9px] uppercase tracking-widest opacity-70">Custom PDF Options</span>
          </motion.button>

          {/* Mode Switcher */}
          <div>
            <label className="block text-[10px] font-bold text-slate-500 uppercase mb-2">Learning Mode</label>
            <div className="flex bg-slate-800 p-1 rounded-xl relative">
              <button 
                onClick={() => toggleViewMode(ViewMode.QUIZ)}
                className={`relative flex-1 py-2 text-xs font-bold rounded-lg transition-all z-10 ${state.viewMode === ViewMode.QUIZ ? 'text-white' : 'text-slate-400 hover:text-slate-200'}`}
              >
                Question Bank
                {state.viewMode === ViewMode.QUIZ && (
                  <motion.div layoutId="mode-bg" className="absolute inset-0 bg-indigo-600 rounded-lg -z-10 shadow-lg" />
                )}
              </button>
              <button 
                onClick={() => toggleViewMode(ViewMode.FLASHCARDS)}
                className={`relative flex-1 py-2 text-xs font-bold rounded-lg transition-all z-10 ${state.viewMode === ViewMode.FLASHCARDS ? 'text-white' : 'text-slate-400 hover:text-slate-200'}`}
              >
                Flashcards
                {state.viewMode === ViewMode.FLASHCARDS && (
                  <motion.div layoutId="mode-bg" className="absolute inset-0 bg-indigo-600 rounded-lg -z-10 shadow-lg" />
                )}
              </button>
            </div>
          </div>

          {/* PDF Analysis Tool */}
          <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700">
            <label className="block text-[10px] font-bold text-indigo-400 uppercase mb-3 flex items-center">
              <svg className="w-3 h-3 mr-1" fill="currentColor" viewBox="0 0 20 20"><path d="M9 2a2 2 0 00-2 2v8a2 2 0 002 2h6a2 2 0 002-2V6.414A2 2 0 0016.414 5L14 2.586A2 2 0 0012.586 2H9z"></path><path d="M3 8a2 2 0 012-2v10h8a2 2 0 01-2 2H5a2 2 0 01-2-2V8z"></path></svg>
              PDF Smart Analysis
            </label>
            {!state.uploadedFile ? (
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-full border-2 border-dashed border-slate-600 rounded-lg p-4 text-center hover:border-indigo-500 hover:bg-slate-800 transition-all group"
              >
                <div className="text-slate-400 group-hover:text-indigo-400 mb-2 flex justify-center">
                  <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
                </div>
                <p className="text-xs text-slate-300 font-medium">Upload Study PDF</p>
              </button>
            ) : (
              <div className="bg-slate-900 p-3 rounded-lg border border-indigo-500/30 flex items-center justify-between">
                <div className="flex items-center space-x-2 truncate">
                  <div className="bg-indigo-600/20 p-2 rounded text-indigo-400">
                    <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4 4a2 2 0 012-2h4.586A2 2 0 0112 2.586L15.414 6A2 2 0 0116 7.414V16a2 2 0 01-2 2H6a2 2 0 01-2-2V4z" clipRule="evenodd"></path></svg>
                  </div>
                  <span className="text-xs font-medium text-slate-200 truncate">{state.uploadedFile.name}</span>
                </div>
                <button onClick={clearFile} className="text-slate-500 hover:text-rose-400 p-1">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
                </button>
              </div>
            )}
            <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept="application/pdf" className="hidden" />
