import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Flashcard } from '../types';

interface FlashcardSetProps {
  flashcards: Flashcard[];
}

export const FlashcardSet: React.FC<FlashcardSetProps> = ({ flashcards }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [direction, setDirection] = useState(0);

  if (flashcards.length === 0) return null;

  const currentCard = flashcards[currentIndex];

  const handleNext = () => {
    setDirection(1);
    setIsFlipped(false);
    setCurrentIndex((prev) => (prev + 1) % flashcards.length);
  };

  const handlePrev = () => {
    setDirection(-1);
    setIsFlipped(false);
    setCurrentIndex((prev) => (prev - 1 + flashcards.length) % flashcards.length);
  };

  const variants = {
    enter: (direction: number) => ({
      x: direction > 0 ? 300 : -300,
      opacity: 0,
      scale: 0.9
    }),
    center: {
      zIndex: 1,
      x: 0,
      opacity: 1,
      scale: 1
    },
    exit: (direction: number) => ({
      zIndex: 0,
      x: direction < 0 ? 300 : -300,
      opacity: 0,
      scale: 0.9
    })
  };

  return (
    <div className="flex flex-col items-center space-y-8 py-10 overflow-hidden">
      <div className="flex items-center justify-between w-full max-w-lg mb-4 text-slate-500 font-bold text-xs uppercase tracking-widest px-4">
        <span>Concept {currentIndex + 1} of {flashcards.length}</span>
        <motion.span 
          key={currentCard.conceptCategory}
          initial={{ opacity: 0 }} animate={{ opacity: 1 }}
          className="bg-indigo-100 text-indigo-700 px-2 py-1 rounded"
        >
          {currentCard.conceptCategory || 'Revision'}
        </motion.span>
      </div>

      <div className="relative w-full max-w-lg h-80 md:h-96">
        <AnimatePresence initial={false} custom={direction}>
          <motion.div 
            key={currentIndex}
            custom={direction}
            variants={variants}
            initial="enter"
            animate="center"
            exit="exit"
            transition={{
              x: { type: "spring", stiffness: 300, damping: 30 },
              opacity: { duration: 0.2 }
            }}
            className="absolute inset-0 flashcard-container group cursor-pointer"
            onClick={() => setIsFlipped(!isFlipped)}
          >
            <div className={`flashcard-inner relative w-full h-full text-center transition-transform duration-500 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>

              {/* Front of Card */}
              <div className="flashcard-front absolute inset-0 w-full h-full backface-hidden bg-white border-2 border-slate-200 rounded-3xl shadow-xl flex flex-col items-center justify-center p-8 space-y-6">
                <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center mb-2">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg>
                </div>
                <h2 className="text-2xl font-black text-slate-800 tracking-tight">{currentCard.termEn}</h2>
                <h2 className="text-3xl font-bold text-indigo-900 odia-font">{currentCard.termOd}</h2>
                <p className="absolute bottom-6 text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em] animate-pulse">Click to Reveal Definition</p>
              </div>

              {/* Back of Card */}
              <div className="flashcard-back absolute inset-0 w-full h-full backface-hidden rotate-y-180 bg-slate-900 border-2 border-indigo-500/50 rounded-3xl shadow-2xl flex flex-col items-center justify-center p-10 overflow-y-auto custom-scrollbar">
                <div className="space-y-6 w-full">
                  <div className="space-y-2">
                    <p className="text-indigo-400 text-[10px] font-black uppercase tracking-widest text-left">Definition (EN)</p>
                    <p className="text-white text-lg font-medium leading-relaxed text-left">{currentCard.definitionEn}</p>
                  </div>
                  <div className="h-px bg-slate-800 w-full"></div>
                  <div className="space-y-2 odia-font">
                    <p className="text-indigo-400 text-[10px] font-black uppercase tracking-widest text-left">ବ୍ୟାଖ୍ୟା (ଓଡ଼ିଆ)</p>
                    <p className="text-slate-200 text-xl font-medium leading-relaxed text-left">{currentCard.definitionOd}</p>
                  </div>
                </div>
              </div>

            </div>
          </motion.div>
        </AnimatePresence>
      </div>

      <div className="flex items-center space-x-6 z-10">
        <motion.button 
          whileHover={{ scale: 1.1 }}
          whileTap={{ scale: 0.9 }}
          onClick={(e) => { e.stopPropagation(); handlePrev(); }}
          className="w-14 h-14 rounded-full bg-white border border-slate-200 flex items-center justify-center text-slate-600 hover:bg-slate-50 hover:text-indigo-600 shadow-md transition-all"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 19l-7-7 7-7"></path></svg>
        </motion.button>
        <motion.button 
          whileHover={{ scale: 1.1 }}
          whileTap={{ scale: 0.9 }}
          onClick={(e) => { e.stopPropagation(); handleNext(); }}
          className="w-14 h-14 rounded-full bg-slate-900 flex items-center justify-center text-white hover:bg-indigo-600 shadow-xl transition-all"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"></path></svg>
        </motion.button>
      </div>

      <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">Tip: Use flashcards for 5 minutes daily to boost memory</p>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Category, AppState, Question, Flashcard, FileData, ViewMode, PdfLanguage } from './types';
import { SYLLABUS_DATA } from './constants';
import { generatePracticeQuestions, generateFlashcards } from './services/geminiService';
import { QuestionCard } from './components/QuestionCard';
import { FlashcardSet } from './components/FlashcardSet';

const PDF_STEPS = [
  "Building content structure...",
  "Applying bilingual styles...",
  "Rendering Odia scripts...",
  "Finalizing PDF snapshot...",
  "Downloading to device..."
];

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    category: Category.CAT_I,
    selectedSectionId: SYLLABUS_DATA[Category.CAT_I][0].id,
    questions: [],
    flashcards: [],
    viewMode: ViewMode.QUIZ,
    loading: false,
    error: null,
    language: 'en',
    uploadedFile: null,
    studyMode: true,
    pdfConfig: {
      language: 'both',
      startRange: 1,
      endRange: 20
    }
  });

  const [pdfPrepStep, setPdfPrepStep] = useState<number>(-1);
  const [showPdfSettings, setShowPdfSettings] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const fetchData = useCallback(async (sectionId: string, category: Category, mode: ViewMode, fileToUse?: FileData | null) => {
    const section = SYLLABUS_DATA[category].find(s => s.id === sectionId);
    if (!section) return;

    setState(prev => ({ ...prev, loading: true, error: null }));

    try {
      const activeFile = fileToUse !== undefined ? fileToUse : state.uploadedFile;

      if (mode === ViewMode.QUIZ) {
        const qs = await generatePracticeQuestions(section.title, section.topics, category, activeFile);
        setState(prev => ({ 
          ...prev, 
          questions: qs, 
          loading: false,
          pdfConfig: { ...prev.pdfConfig, endRange: qs.length }
        }));
      } else {
        const cards = await generateFlashcards(section.title, section.topics, category, activeFile);
        setState(prev => ({ ...prev, flashcards: cards, loading: false }));
      }
    } catch (err) {
      setState(prev => ({ ...prev, error: "Failed to load content. Please try again.", loading: false }));
    }
  }, [state.uploadedFile]);

  useEffect(() => {
    fetchData(state.selectedSectionId, state.category, state.viewMode);
  }, []);

  const handleCategoryChange = (cat: Category) => {
    const firstSectionId = SYLLABUS_DATA[cat][0].id;
    setState(prev => ({ ...prev, category: cat, selectedSectionId: firstSectionId }));
    fetchData(firstSectionId, cat, state.viewMode);
  };

  const handleSectionChange = (id: string) => {
    setState(prev => ({ ...prev, selectedSectionId: id }));
    fetchData(id, state.category, state.viewMode);
  };

  const toggleViewMode = (mode: ViewMode) => {
    if (mode === state.viewMode) return;
    setState(prev => ({ ...prev, viewMode: mode }));

    if ((mode === ViewMode.QUIZ && state.questions.length === 0) || 
        (mode === ViewMode.FLASHCARDS && state.flashcards.length === 0)) {
      fetchData(state.selectedSectionId, state.category, mode);
    }
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (file.type !== 'application/pdf') {
      alert('Please upload a PDF file.');
      return;
    }

    const reader = new FileReader();
    reader.onload = () => {
      const base64 = (reader.result as string).split(',')[1];
      const newFileData = {
        data: base64,
        mimeType: file.type,
        name: file.name
      };
      setState(prev => ({ ...prev, uploadedFile: newFileData, questions: [], flashcards: [] }));
      fetchData(state.selectedSectionId, state.category, state.viewMode, newFileData);
    };
    reader.readAsDataURL(file);
  };

  const clearFile = () => {
    setState(prev => ({ ...prev, uploadedFile: null, questions: [], flashcards: [] }));
    if (fileInputRef.current) fileInputRef.current.value = '';
    fetchData(state.selectedSectionId, state.category, state.viewMode, null);
  };

  const startPDFProcess = async () => {
    const targetQuestions = state.questions.slice(state.pdfConfig.startRange - 1, state.pdfConfig.endRange);

    if (targetQuestions.length === 0) {
      alert("No questions selected for export.");
      return;
    }

    setShowPdfSettings(false);
    setPdfPrepStep(0);

    const currentSection = SYLLABUS_DATA[state.category].find(s => s.id === state.selectedSectionId);
    const exportContainer = document.getElementById('pdf-export-container');
    if (!exportContainer) return;

    // Build Injected HTML with inline styles for guaranteed PDF visibility
    const contentHtml = `
      <div style="font-family: 'Inter', sans-serif; color: black; background: white; padding: 20px;">
        <div class="pdf-header">
          <h1 style="font-size: 20pt; font-weight: 800; text-transform: uppercase; margin-bottom: 5px;">Odisha Junior Teacher (Schematic)</h1>
          <p style="font-size: 14pt; font-weight: 700; margin-bottom: 15px; color: #1e293b;">Subject Mastery: ${currentSection?.title || 'Worksheet'}</p>
          <div style="display: flex; justify-content: space-between; font-size: 10pt; font-weight: bold; border-top: 1pt solid #cbd5e1; padding-top: 10px;">
             <span>Exam: JT Recruitment</span>
             <span>Category: ${state.category === Category.CAT_I ? 'I (Primary)' : 'II (Upper Primary)'}</span>
             <span>Items: ${targetQuestions.length}</span>
          </div>
        </div>

        <div id="pdf-questions-list">
          ${targetQuestions.map((q, idx) => {
            const showEn = state.pdfConfig.language === 'both' || state.pdfConfig.language === 'en';
            const showOd = state.pdfConfig.language === 'both' || state.pdfConfig.language === 'od';
            const realIdx = (state.pdfConfig.startRange - 1) + idx + 1;

            return `
              <div class="pdf-question-card">
                <div style="margin-bottom: 10px; font-weight: 800; color: #4f46e5; text-transform: uppercase; font-size: 9pt;">
                  Item No. ${realIdx}
                </div>

                <div style="margin-bottom: 15px;">
                  ${showEn ? `<div style="font-size: 13pt; font-weight: 700; margin-bottom: 6px; color: #0f172a;">${q.questionEn}</div>` : ''}
                  ${showOd ? `<div class="odia-font" style="font-size: 15pt; font-weight: 600; color: #1e1b4b; border-left: 3pt solid #e0e7ff; padding-left: 10px;">${q.questionOd}</div>` : ''}
                </div>

                <div style="margin-bottom: 15px;">
                  ${q.optionsEn.map((optEn, optIdx) => {
                    const optOd = q.optionsOd[optIdx];
                    const label = String.fromCharCode(65 + optIdx);
                    return `
                      <div style="display: flex; align-items: flex-start; margin-bottom: 8px;">
                        <span style="width: 25px; font-weight: bold; color: #64748b; font-size: 11pt;">${label}.</span>
                        <div style="flex: 1;">
                          ${showEn ? `<div style="font-weight: 600; font-size: 11pt; color: #334155;">${optEn}</div>` : ''}
                          ${showOd ? `<div class="odia-font" style="font-weight: 500; font-size: 12pt; color: #4338ca;">${optOd}</div>` : ''}
                        </div>
                      </div>
                    `;
                  }).join('')}
                </div>

                <div style="background: #f8fafc; padding: 12px; border-radius: 6px; border: 1pt dashed #cbd5e1;">
                  <div style="font-size: 8pt; font-weight: 800; color: #059669; text-transform: uppercase; margin-bottom: 5px;">Analysis & Correct Key</div>
                  <div style="font-weight: 800; color: #1e293b; margin-bottom: 8px; font-size: 11pt;">Correct: ${String.fromCharCode(65 + q.correctOptionIndex)}</div>
                  ${showEn ? `<p style="font-size: 10pt; color: #475569; margin-bottom: 5px; line-height: 1.4;">${q.explanationEn}</p>` : ''}
                  ${showOd ? `<p class="odia-font" style="font-size: 11pt; color: #475569; line-height: 1.4;">${q.explanationOd}</p>` : ''}
                </div>
              </div>
            `;
          }).join('')}
        </div>

        <div style="text-align: center; margin-top: 20px; font-size: 9pt; color: #94a3b8; font-weight: bold; border-top: 1pt solid #f1f5f9; padding-top: 10px;">
          Practice Set Generated by Odisha JT Prep Hub - Official Syllabus Alignment
        </div>
      </div>
    `;

    // 1. Inject content
    exportContainer.innerHTML = contentHtml;
    setPdfPrepStep(1);

    // 2. Wait for Fonts and Painting (Critical for preventing blank pages)
    await new Promise(r => setTimeout(r, 1200));
    setPdfPrepStep(2);

    // 3. Final Check on Font Ready
    try {
      if (document.fonts) await document.fonts.ready;
    } catch (e) {
      console.warn("Font loading check failed, proceeding anyway...");
    }
    setPdfPrepStep(3);

    // 4. Run PDF Generation
    const fileName = `JT_EXAM_PREP_${(currentSection?.title || 'Set').replace(/\s+/g, '_')}.pdf`;

    const opt = {
      margin: [10, 10, 10, 10], 
      filename: fileName,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { 
        scale: 2, 
        useCORS: true, 
        letterRendering: true,
        logging: false,
        backgroundColor: '#ffffff',
        width: 750,
        windowWidth: 750
      },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };

    setPdfPrepStep(4);

    try {
      const element = document.getElementById('pdf-export-container');
      if (element) {
        await (window as any).html2pdf().set(opt).from(element).save();
      }
    } catch (err) {
      console.error("PDF Generation failed:", err);
      alert("Something went wrong during PDF creation. Please try again.");
    } finally {
      setPdfPrepStep(-1);
      if (exportContainer) exportContainer.innerHTML = '';
    }
  };

  const currentSection = SYLLABUS_DATA[state.category].find(s => s.id === state.selectedSectionId);
  const filteredQuestions = state.questions.slice(state.pdfConfig.startRange - 1, state.pdfConfig.endRange);

  return (
    <div className="min-h-screen flex flex-col md:flex-row overflow-x-hidden">
      {/* PDF PREPARATION OVERLAY */}
      <AnimatePresence>
        {pdfPrepStep >= 0 && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-[100] glass-prep flex items-center justify-center p-6 text-white"
          >
            <div className="max-w-md w-full bg-slate-900 rounded-3xl p-8 border border-slate-700 shadow-2xl relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-1 bg-slate-800">
                <motion.div 
                  initial={{ width: "0%" }}
                  animate={{ width: `${((pdfPrepStep + 1) / PDF_STEPS.length) * 100}%` }}
                  className="h-full bg-emerald-500 shadow-[0_0_15px_rgba(16,185,129,0.5)]"
                />
              </div>

              <div className="flex flex-col items-center">
                <div className="w-16 h-16 mb-6 bg-emerald-500/10 rounded-2xl flex items-center justify-center">
                  <motion.svg 
                    animate={{ rotate: 360 }}
                    transition={{ duration: 1.5, repeat: Infinity, ease: "linear" }}
                    className="w-10 h-10 text-emerald-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"
                  >
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path>
                  </motion.svg>
                </div>

                <h2 className="text-xl font-black mb-1">Generating PDF Document</h2>
                <p className="text-slate-400 text-sm mb-8">This may take a moment for large sets...</p>

                <div className="w-full space-y-3">
                  {PDF_STEPS.map((step, idx) => (
                    <motion.div 
                      key={idx}
                      initial={{ opacity: 0.3 }}
                      animate={{ 
                        opacity: idx === pdfPrepStep ? 1 : idx < pdfPrepStep ? 0.6 : 0.2,
                        scale: idx === pdfPrepStep ? 1.05 : 1
                      }}
                      className="flex items-center space-x-3 text-xs font-bold"
                    >
                      <div className={`w-5 h-5 rounded-full flex items-center justify-center flex-shrink-0 transition-all ${idx < pdfPrepStep ? 'bg-emerald-500' : idx === pdfPrepStep ? 'bg-emerald-400 animate-pulse ring-4 ring-emerald-400/20' : 'bg-slate-700'}`}>
                        {idx < pdfPrepStep ? (
                          <svg className="w-3 h-3 text-white" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd"></path></svg>
                        ) : <span className="text-[8px]">{idx + 1}</span>}
                      </div>
                      <span className={idx === pdfPrepStep ? 'text-white' : 'text-slate-500'}>{step}</span>
                    </motion.div>
                  ))}
                </div>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* PDF SETTINGS MODAL */}
      <AnimatePresence>
        {showPdfSettings && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-[90] bg-slate-950/80 backdrop-blur-md flex items-center justify-center p-6 no-print"
          >
            <motion.div 
              initial={{ scale: 0.9, y: 20 }}
              animate={{ scale: 1, y: 0 }}
              className="bg-white rounded-3xl p-8 max-w-lg w-full shadow-2xl border border-slate-200"
            >
              <div className="flex justify-between items-center mb-6">
                <div>
                  <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight">PDF Export Options</h3>
                  <p className="text-xs text-slate-500 font-bold">Configure your custom worksheet</p>
                </div>
                <button onClick={() => setShowPdfSettings(false)} className="text-slate-400 hover:text-rose-500 p-2 transition-colors">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
                </button>
              </div>

              <div className="space-y-6">
                {/* Language Filter */}
                <div>
                  <label className="block text-[10px] font-bold text-slate-500 uppercase mb-3 tracking-widest">Language Content</label>
                  <div className="grid grid-cols-3 gap-2">
                    {(['both', 'en', 'od'] as PdfLanguage[]).map(l => (
                      <button
                        key={l}
                        onClick={() => setState(p => ({ ...p, pdfConfig: { ...p.pdfConfig, language: l }}))}
                        className={`py-3 px-3 text-xs font-bold rounded-xl border-2 transition-all ${state.pdfConfig.language === l ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg shadow-indigo-200' : 'border-slate-100 text-slate-500 hover:border-indigo-100 bg-slate-50'}`}
                      >
                        {l === 'both' ? 'Bilingual' : l === 'en' ? 'English Only' : 'Odia Only'}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Range Selection */}
                <div>
                  <label className="block text-[10px] font-bold text-slate-500 uppercase mb-3 tracking-widest">Question Range (Total Available: {state.questions.length})</label>
                  <div className="flex items-center space-x-4 bg-slate-50 p-4 rounded-2xl border-2 border-slate-100">
                    <div className="flex-1">
                      <p className="text-[10px] text-slate-400 mb-1 font-bold">START AT</p>
                      <input 
                        type="number" 
                        min="1" 
                        max={state.questions.length}
                        value={state.pdfConfig.startRange}
                        onChange={(e) => setState(p => ({ ...p, pdfConfig: { ...p.pdfConfig, startRange: Math.max(1, parseInt(e.target.value) || 1)}}))}
                        className="w-full bg-white border-2 border-slate-200 rounded-xl px-4 py-3 text-sm font-bold focus:border-indigo-500 outline-none transition-colors"
                      />
                    </div>
                    <div className="flex-shrink-0 pt-4 text-slate-300">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 5l7 7m0 0l-7 7m7-7H3"></path></svg>
                    </div>
                    <div className="flex-1">
                      <p className="text-[10px] text-slate-400 mb-1 font-bold">END AT</p>
                      <input 
                        type="number" 
                        min={state.pdfConfig.startRange} 
                        max={state.questions.length}
                        value={state.pdfConfig.endRange}
                        onChange={(e) => setState(p => ({ ...p, pdfConfig: { ...p.pdfConfig, endRange: Math.min(state.questions.length, parseInt(e.target.value) || state.questions.length)}}))}
                        className="w-full bg-white border-2 border-slate-200 rounded-xl px-4 py-3 text-sm font-bold focus:border-indigo-500 outline-none transition-colors"
                      />
                    </div>
                  </div>
                </div>

                <motion.button
                  whileHover={{ scale: 1.02 }}
                  whileTap={{ scale: 0.98 }}
                  onClick={startPDFProcess}
                  className="w-full bg-indigo-600 hover:bg-indigo-700 text-white py-5 rounded-2xl font-black text-sm shadow-xl shadow-indigo-900/20 transition-all flex items-center justify-center space-x-2"
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>
                  <span>START PDF DOWNLOAD</span>
                </motion.button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Sidebar */}
      <aside className="w-full md:w-80 bg-slate-900 text-slate-100 flex-shrink-0 flex flex-col h-auto md:h-screen md:sticky md:top-0 border-r border-slate-800 z-20">
        <div className="p-6 border-b border-slate-800">
          <motion.h1 
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            className="text-xl font-bold flex items-center"
          >
            <span className="bg-indigo-600 p-2 rounded-lg mr-3 shadow-lg shadow-indigo-500/20">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253"></path>
              </svg>
            </span>
            Junior Teacher Prep
          </motion.h1>
          <p className="text-slate-400 text-[10px] mt-2 uppercase tracking-[0.2em] font-black">Bilingual Mastery Hub</p>
        </div>

        <div className="p-4 space-y-6 flex-1 overflow-y-auto custom-scrollbar">
          {/* Main Download Action */}
          <motion.button
             whileHover={{ scale: 1.02 }}
             whileTap={{ scale: 0.95 }}
             onClick={() => setShowPdfSettings(true)}
             className="w-full bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl py-4 flex flex-col items-center justify-center font-black shadow-xl shadow-indigo-900/30 transition-all no-print mb-4 border border-indigo-500/50"
          >
             <div className="flex items-center space-x-2 text-sm mb-0.5">
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
               <span>SAVE TO PDF</span>
